function useReveal() {
  useEffect(() => {
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (e.isIntersecting) {
            e.target.classList.add("visible");
            io.unobserve(e.target);
          }
        });
      },
      { threshold: 0.1 }
    );
    document.querySelectorAll(".reveal").forEach((el) => io.observe(el));
    return () => io.disconnect();
  }, []);
}

function Navbar() {
  const [open, setOpen] = useState(false);
  const [activeSection, setActiveSection] = useState("home");

  useEffect(() => {
    const handleScroll = () => {
      const sections = ["home", "about", "skills", "projects", "experience", "certifications", "contact"];
      const scrollY = window.scrollY;
      sections.forEach((id) => {
        const el = document.getElementById(id);
        if (el) {
          const top = el.offsetTop - 100;
          if (scrollY >= top && scrollY < top + el.offsetHeight) {
            setActiveSection(id);
          }
        }
      });
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const scrollTo = (id) => {
    setOpen(false);
    document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
  };

  const navItems = ["home", "about", "skills", "projects", "experience", "certifications"];

  return (
    <nav className="navbar">
      <div className="logo">Subathra<span>.dev</span></div>
      <ul className={`nav-links${open ? " open" : ""}`}>
        {navItems.map((item) => (
          <li key={item}>
            <a
              href={`#${item}`}
              className={activeSection === item ? "active" : ""}
              onClick={(e) => { e.preventDefault(); scrollTo(item); }}
            >
              {item.charAt(0).toUpperCase() + item.slice(1)}
            </a>
          </li>
        ))}
        <li>
          <a href="#contact" className="nav-cta" onClick={(e) => { e.preventDefault(); scrollTo("contact"); }}>
            Contact
          </a>
        </li>
      </ul>
      <div className="hamburger" onClick={() => setOpen(!open)}>
        <span className={open ? "open" : ""}></span>
        <span className={open ? "open" : ""}></span>
        <span className={open ? "open" : ""}></span>
      </div>
    </nav>
  );
}

